#include <iostream>
#include <sstream>
#include <iomanip>

class Rectangle {
private:
    double width;
    double height;

public:
    Rectangle(double w, double h) : width(w), height(h) {}

    double getArea() {
        return width * height;
    }
};

int main() {
    double w, h;
    std::cout << std::fixed << std::setprecision(2);
    while (std::cin >> w >> h) {
        Rectangle r(w, h);
        std::cout << r.getArea() << std::endl;
    }
    return 0;
}
